const body = $input.first().json.body || {};
const message = (body.message || '').trim();
const session_id = (body.session_id || '').trim();

// Health-check: отдаём pong без вызова LLM
if (message === 'ping') {
  return [{json: {valid: 0, error: 'pong'}}];
}

if (!message || message.length < 2) {
  return [{json: {valid: 0, error: 'Введите сообщение (минимум 2 символа)'}}];
}

if (!session_id) {
  return [{json: {valid: 0, error: 'Поле session_id обязательно'}}];
}

if (message.length > 10000) {
  return [{json: {valid: 0, error: 'Слишком длинный запрос (максимум 10000 символов)'}}];
}

return [{json: {valid: 1, message: message, session_id: session_id}}];

// Резюме из chat_summaries
const summaryRows = $('Загрузить резюме').all();
let summary = '';
let messagesSummarized = 0;
if (summaryRows.length > 0 && summaryRows[0].json.summary_text) {
  summary = summaryRows[0].json.summary_text;
  messagesSummarized = summaryRows[0].json.messages_summarized || 0;
}

// Последние 30 сообщений (загружены в обратном порядке, переворачиваем)
const historyRows = $('Загрузить историю').all().reverse();
let historyContext = '';
if (historyRows.length > 0) {
  const lines = historyRows.map(item => {
    const role = item.json.role === 'user' ? 'Пользователь' : 'Ассистент';
    return role + ': ' + (item.json.content || '');
  });
  historyContext = lines.join('\n');
}

return [{json: {
  summary: summary,
  messagesSummarized: messagesSummarized,
  historyContext: historyContext,
  historyCount: historyRows.length,
  message: $('Валидация').first().json.message,
  session_id: $('Валидация').first().json.session_id
}}];

const totalRow = $input.first().json;
const total = parseInt(totalRow.total || '0', 10);
const summarized = $('Агрегация').first().json.messagesSummarized || 0;

// Если всего сообщений > 30 И есть несжатые старые сообщения
const unsummarized = total - 30 - summarized;

if (unsummarized > 0) {
  // Нужно сжать: загрузить сообщения с offset summarized, limit unsummarized
  return [{json: {needsCompression: true, total: total, summarized: summarized, toCompress: unsummarized}}];
}

return [{json: {needsCompression: false, total: total}}];

let newSummary = '';
try {
  newSummary = $input.first().json.output[0].content[0].text.trim();
} catch(e) {
  // GigaChat не ответил — оставляем старое резюме
  newSummary = $('Агрегация').first().json.summary || '';
}

const sessionId = $('Агрегация').first().json.session_id;
const oldSummarized = $('Нужно сжатие?').first().json.summarized || 0;
const compressed = $('Нужно сжатие?').first().json.toCompress || 0;
const newSummarized = oldSummarized + compressed;

// Экранируем одинарные кавычки
const safeSummary = newSummary.replaceAll("'", "''");

return [{json: {
  upsertQuery: "INSERT INTO chat_summaries (session_id, summary_text, messages_summarized, updated_at) VALUES ('" + sessionId + "', '" + safeSummary + "', " + newSummarized + ", NOW()) ON CONFLICT (session_id) DO UPDATE SET summary_text = '" + safeSummary + "', messages_summarized = " + newSummarized + ", updated_at = NOW()",
  newSummary: newSummary
}}];

try {
  const raw = $input.first().json;
  if (raw.error) {
    return [{ json: { response: 'Не удалось обработать запрос. Попробуйте ещё раз.' } }];
  }
  const text = raw.output[0].content[0].text;
  return [{ json: { response: text.trim() } }];
} catch(e) {
  return [{ json: { response: 'Ошибка обработки ответа.' } }];
}
